"use strict";(self.webpackChunk_=self.webpackChunk_||[]).push([["5059"],{11737(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"prompt-caching","metadata":{"permalink":"/ai-eng/blog/prompt-caching","source":"@site/blog/2026-07-01-prompt-caching.md","title":"\uD504\uB86C\uD504\uD2B8 \uCE90\uC2F1: \uD488\uC9C8\uC740 \uC720\uC9C0\uD558\uACE0 LLM \uC6B4\uC601 \uBE44\uC6A9\uC740 \uD68D\uAE30\uC801\uC73C\uB85C \uC904\uC774\uB294 \uBC95","description":"AI \uC11C\uBE44\uC2A4\uB97C \uC6B4\uC601\uD558\uBA70 \uAC00\uC7A5 \uD070 \uACE0\uBBFC \uC911 \uD558\uB098\uB294 \'\uC785\uB825 \uD1A0\uD070 \uBE44\uC6A9\'\uACFC \'\uC751\uB2F5 \uC18D\uB3C4\'\uC785\uB2C8\uB2E4. \uAE34 \uBB38\uC11C\uB97C \uCC38\uACE0\uD558\uAC70\uB098 \uBCF5\uC7A1\uD55C \uC2DC\uC2A4\uD15C \uC9C0\uC2DC\uBB38\uC744 \uC0AC\uC6A9\uD558\uB294 \uC11C\uBE44\uC2A4\uB77C\uBA74 \uC774 \uACE0\uBBFC\uC740 \uB354\uC6B1 \uAE4A\uC5B4\uC9C0\uC8E0. \uB2F5\uBCC0 \uD488\uC9C8\uC744 \uC704\uD574 \uBB38\uB9E5(Context)\uC744 \uC904\uC77C \uC218\uB294 \uC5C6\uACE0, \uBE44\uC6A9\uC740 \uAC10\uB2F9\uD558\uAE30 \uBC84\uAC70\uC6B8 \uB54C \uAC00\uC7A5 \uBA3C\uC800 \uC2DC\uB3C4\uD574\uC57C \uD560 \uCD5C\uC801\uD654 \uC804\uB7B5, \uBC14\uB85C \uD504\uB86C\uD504\uD2B8 \uCE90\uC2F1(Prompt Caching)\uC744 \uC18C\uAC1C\uD569\uB2C8\uB2E4.","date":"2026-07-01T00:00:00.000Z","tags":[{"inline":true,"label":"llm","permalink":"/ai-eng/blog/tags/llm"},{"inline":true,"label":"cost-optimization","permalink":"/ai-eng/blog/tags/cost-optimization"},{"inline":true,"label":"prompt-engineering","permalink":"/ai-eng/blog/tags/prompt-engineering"}],"readingTime":2.26,"hasTruncateMarker":true,"authors":[{"name":"jeonck","title":"AI \uC5D4\uC9C0\uB2C8\uC5B4\uB9C1","url":"https://github.com/jeonck","page":null,"key":"jeonck"}],"frontMatter":{"slug":"prompt-caching","title":"\uD504\uB86C\uD504\uD2B8 \uCE90\uC2F1: \uD488\uC9C8\uC740 \uC720\uC9C0\uD558\uACE0 LLM \uC6B4\uC601 \uBE44\uC6A9\uC740 \uD68D\uAE30\uC801\uC73C\uB85C \uC904\uC774\uB294 \uBC95","authors":["jeonck"],"tags":["llm","cost-optimization","prompt-engineering"]},"unlisted":false},"content":"AI \uC11C\uBE44\uC2A4\uB97C \uC6B4\uC601\uD558\uBA70 \uAC00\uC7A5 \uD070 \uACE0\uBBFC \uC911 \uD558\uB098\uB294 \'\uC785\uB825 \uD1A0\uD070 \uBE44\uC6A9\'\uACFC \'\uC751\uB2F5 \uC18D\uB3C4\'\uC785\uB2C8\uB2E4. \uAE34 \uBB38\uC11C\uB97C \uCC38\uACE0\uD558\uAC70\uB098 \uBCF5\uC7A1\uD55C \uC2DC\uC2A4\uD15C \uC9C0\uC2DC\uBB38\uC744 \uC0AC\uC6A9\uD558\uB294 \uC11C\uBE44\uC2A4\uB77C\uBA74 \uC774 \uACE0\uBBFC\uC740 \uB354\uC6B1 \uAE4A\uC5B4\uC9C0\uC8E0. \uB2F5\uBCC0 \uD488\uC9C8\uC744 \uC704\uD574 \uBB38\uB9E5(Context)\uC744 \uC904\uC77C \uC218\uB294 \uC5C6\uACE0, \uBE44\uC6A9\uC740 \uAC10\uB2F9\uD558\uAE30 \uBC84\uAC70\uC6B8 \uB54C \uAC00\uC7A5 \uBA3C\uC800 \uC2DC\uB3C4\uD574\uC57C \uD560 \uCD5C\uC801\uD654 \uC804\uB7B5, \uBC14\uB85C \uD504\uB86C\uD504\uD2B8 \uCE90\uC2F1(Prompt Caching)\uC744 \uC18C\uAC1C\uD569\uB2C8\uB2E4.\\n\\n{/* truncate */}\\n\\n## 1. \uD504\uB86C\uD504\uD2B8 \uCE90\uC2F1\uC774\uB780 \uBB34\uC5C7\uC778\uAC00?\\n\\n\uB9CE\uC740 \uBD84\uC774 \uD504\uB86C\uD504\uD2B8 \uCE90\uC2F1\uC744 \\"\uC774\uC804 \uB300\uD654 \uB0B4\uC6A9\uC744 \uC800\uC7A5\uD588\uB2E4\uAC00 \uC7AC\uC0AC\uC6A9\uD558\uB294 \uAC83\\"\uC73C\uB85C \uC624\uD574\uD558\uACE4 \uD569\uB2C8\uB2E4. \uD558\uC9C0\uB9CC \uC774\uB294 \uC5C4\uBC00\uD788 \uB9D0\uD558\uBA74 \uC751\uB2F5 \uCE90\uC2F1(Response Caching)\uC5D0 \uAC00\uAE5D\uC2B5\uB2C8\uB2E4.\\n\\n\uD504\uB86C\uD504\uD2B8 \uCE90\uC2F1\uC758 \uD575\uC2EC\uC740 **\'\uC785\uB825\uC758 \uBC18\uBCF5\uB418\uB294 \uC55E\uBD80\uBD84(Prefix)\uC744 \uCC98\uB9AC\uD55C \uC911\uAC04 \uACB0\uACFC\uAC12\uC744 \uC7AC\uC0AC\uC6A9\'**\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4.\\n\\nLLM\uC740 \uD504\uB86C\uD504\uD2B8\uB97C \uCC98\uB9AC\uD560 \uB54C \uB0B4\uBD80\uC801\uC73C\uB85C \uBC29\uB300\uD55C \uC5F0\uC0B0 \uACFC\uC815\uC744 \uAC70\uCCD0 \uD14D\uC2A4\uD2B8\uB97C \uC774\uD574\uD569\uB2C8\uB2E4. \uC774\uB54C \uB9E4\uBC88 \uAC19\uC740 \uC9C0\uC2DC\uBB38\uC774\uB098 \uADDC\uC815 \uBB38\uC11C\uB97C \uCC98\uC74C\uBD80\uD130 \uB05D\uAE4C\uC9C0 \uB2E4\uC2DC \uACC4\uC0B0\uD558\uB294 \uAC83\uC740 \uBE44\uD6A8\uC728\uC801\uC785\uB2C8\uB2E4. \uD504\uB86C\uD504\uD2B8 \uCE90\uC2F1\uC740 \uC774 \'\uBC18\uBCF5\uB418\uB294 \uC55E\uBD80\uBD84\'\uC744 \uC2DC\uC2A4\uD15C \uBA54\uBAA8\uB9AC\uC5D0 \uC800\uC7A5\uD574\uB450\uC5C8\uB2E4\uAC00, \uB2E4\uC74C \uC694\uCCAD \uC2DC \uD574\uB2F9 \uB0B4\uC6A9\uC744 \uB2E4\uC2DC \uACC4\uC0B0\uD558\uC9C0 \uC54A\uACE0 \uC989\uC2DC \uBD88\uB7EC\uC624\uB294 \uAE30\uC220\uC785\uB2C8\uB2E4.\\n\\n## 2. \uC2E4\uC81C \uD6A8\uACFC: Care Access\uC758 \uC0AC\uB840\\n\\n\uC2E4\uC81C \uD604\uC7A5\uC5D0\uC11C\uB294 \uC5B4\uB5A4 \uD6A8\uACFC\uAC00 \uC788\uC744\uAE4C\uC694? \uC758\uB8CC \uAE30\uB85D \uBD84\uC11D \uC11C\uBE44\uC2A4\uC778 Care Access\uB294 Amazon Bedrock\uC758 \uD504\uB86C\uD504\uD2B8 \uCE90\uC2F1\uC744 \uB3C4\uC785\uD558\uC5EC \uB2E4\uC74C\uACFC \uAC19\uC740 \uB180\uB77C\uC6B4 \uC131\uACFC\uB97C \uAC70\uB450\uC5C8\uC2B5\uB2C8\uB2E4.\\n\\n- **\uBE44\uC6A9 \uC808\uAC10**: \uC804\uCCB4 \uCC98\uB9AC \uBE44\uC6A9 86% \uC808\uAC10\\n- **\uC18D\uB3C4 \uD5A5\uC0C1**: \uAE30\uB85D\uB2F9 \uCC98\uB9AC \uC2DC\uAC04 66% \uB2E8\uCD95\\n\\n\uC758\uB8CC \uAE30\uB85D\uCC98\uB7FC \uAE38\uACE0 \uBC18\uBCF5\uC801\uC778 \uBB38\uC11C(\uCEE8\uD14D\uC2A4\uD2B8)\uB97C \uAE30\uBC18\uC73C\uB85C \uB9E4\uBC88 \uC0C8\uB85C\uC6B4 \uC9C8\uBB38\uC744 \uB358\uC9C0\uB294 \uAD6C\uC870\uB77C\uBA74, \uD504\uB86C\uD504\uD2B8 \uCE90\uC2F1\uC740 \uBAA8\uB378 \uBCC0\uACBD \uC5C6\uC774\uB3C4 \uC989\uAC01\uC801\uC778 \uBE44\uC6A9 \uCD5C\uC801\uD654\uB97C \uAC00\uB2A5\uD558\uAC8C \uD569\uB2C8\uB2E4.\\n\\n## 3. \uCE90\uC2DC \uC801\uC911\uB960\uC744 \uB192\uC774\uB294 \uD504\uB86C\uD504\uD2B8 \uC124\uACC4\uBC95\\n\\n\uD504\uB86C\uD504\uD2B8 \uCE90\uC2F1\uC758 \uD6A8\uACFC\uB294 \'\uD504\uB86C\uD504\uD2B8\uB97C \uC5B4\uB5BB\uAC8C \uAD6C\uC870\uD654\uD558\uB290\uB0D0\'\uC5D0 \uB2EC\uB824 \uC788\uC2B5\uB2C8\uB2E4. \uD575\uC2EC \uC6D0\uCE59\uC740 **\\"\uBCC0\uD558\uC9C0 \uC54A\uB294(\uC0C1\uC218) \uC601\uC5ED\uC740 \uC55E\uC5D0, \uB9E4\uBC88 \uBC14\uB00C\uB294(\uBCC0\uC218) \uC601\uC5ED\uC740 \uB4A4\uC5D0\\"** \uBC30\uCE58\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4.\\n\\n### \uB098\uC05C \uC608 (\uCE90\uC2DC \uC801\uC911\uC774 \uC5B4\uB824\uC6B4 \uAD6C\uC870)\\n\\n\uB9E4\uBC88 \uBC14\uB00C\uB294 \uC815\uBCF4(\uB0A0\uC9DC, \uC9C8\uBB38 \uB4F1)\uAC00 \uC55E\uC5D0 \uC788\uC73C\uBA74 \uBAA8\uB378\uC740 \uB9E4\uBC88 \'\uC0C8\uB85C\uC6B4 \uC785\uB825\'\uC73C\uB85C \uD310\uB2E8\uD558\uC5EC \uCE90\uC2DC\uB97C \uD65C\uC6A9\uD558\uC9C0 \uBABB\uD569\uB2C8\uB2E4.\\n\\n```\\n[\uC624\uB298 \uB0A0\uC9DC: 2026-06-24]\\n[\uC9C8\uBB38: \uD734\uAC00 \uC2E0\uCCAD \uBC29\uBC95\uC740?]\\n[\uAE34 \uD68C\uC0AC \uADDC\uC815 \uBB38\uC11C...]\\n```\\n\\n### \uC88B\uC740 \uC608 (\uCE90\uC2DC \uC801\uC911\uC744 \uADF9\uB300\uD654\uD558\uB294 \uAD6C\uC870)\\n\\n\uBC18\uBCF5\uB418\uB294 \uC815\uCC45\uACFC \uC9C0\uC2DC\uBB38\uC744 \uC55E\uC5D0 \uACE0\uC815\uD558\uACE0, \uBCC0\uB3D9 \uB370\uC774\uD130\uB97C \uB4A4\uB85C \uBCF4\uB0C5\uB2C8\uB2E4.\\n\\n```xml\\n<system_policy>\\n[\uB2F5\uBCC0 \uC6D0\uCE59]\\n[\uB2F5\uBCC0 \uD615\uC2DD]\\n[\uD68C\uC0AC \uC778\uC0AC \uADDC\uC815 20\uD398\uC774\uC9C0]\\n</system_policy>\\n\\n<user_info>\\n\uC694\uCCAD\uBCC4 \uC815\uBCF4:\\n\uC624\uB298 \uB0A0\uC9DC: 2026-06-24\\n\uC9C8\uBB38: \uC774 \uADDC\uC815\uC5D0 \uB530\uB974\uBA74 \uD734\uAC00 \uC2E0\uCCAD\uC740 \uC5B4\uB5BB\uAC8C \uD558\uB098\uC694?\\n</user_info>\\n```\\n\\n## 4. \uC2E4\uBB34\uC790\uB97C \uC704\uD55C 3\uB2E8\uACC4 \uC801\uC6A9 \uAC00\uC774\uB4DC\\n\\n1. **\uBC18\uBCF5 \uC601\uC5ED\uACFC \uBCC0\uB3D9 \uC601\uC5ED \uBD84\uB9AC**: \uD604\uC7AC \uC0AC\uC6A9 \uC911\uC778 \uD504\uB86C\uD504\uD2B8\uB97C \uBD84\uC11D\uD558\uC5EC \uACE0\uC815\uAC12(\uC2DC\uC2A4\uD15C \uC9C0\uC2DC\uBB38, \uC815\uCC45, \uB3C4\uAD6C \uC815\uC758)\uACFC \uB3D9\uC801\uAC12(\uC0AC\uC6A9\uC790 \uC9C8\uBB38, \uD604\uC7AC \uC2DC\uAC04)\uC744 \uAD6C\uBD84\uD558\uC138\uC694.\\n2. **\uAD6C\uC870\uD654\uB41C \uD15C\uD50C\uB9BF \uC801\uC6A9**: \uC704 \uC608\uC2DC\uCC98\uB7FC XML \uD0DC\uADF8 \uB4F1\uC744 \uD65C\uC6A9\uD574 \uD504\uB86C\uD504\uD2B8\uB97C \uC815\uD615\uD654\uD569\uB2C8\uB2E4.\\n3. **\uC131\uACFC \uCE21\uC815**: \uC11C\uBE44\uC2A4 API\uC758 Usage Metadata\uB97C \uD655\uC778\uD558\uC5EC \'Cache Read Input Tokens\' \uD56D\uBAA9\uC774 \uBC1C\uC0DD\uD558\uB294\uC9C0 \uBAA8\uB2C8\uD130\uB9C1\uD558\uC138\uC694. \uCE90\uC2DC\uAC00 \uC2E4\uC81C\uB85C \uC801\uC911\uD558\uACE0 \uC788\uB294\uC9C0 \uD655\uC778\uD558\uB294 \uAC83\uC774 \uAC00\uC7A5 \uC911\uC694\uD569\uB2C8\uB2E4.\\n\\n## \uB9C8\uCE58\uBA70\\n\\n\uD504\uB86C\uD504\uD2B8 \uCE90\uC2F1\uC740 AI \uC11C\uBE44\uC2A4\uC758 \'\uC6B4\uC601 \uD6A8\uC728\'\uC744 \uB192\uC774\uB294 \uAC00\uC7A5 \uC815\uC11D\uC801\uC778 \uBC29\uBC95\uC785\uB2C8\uB2E4. \uBAA8\uB378\uC744 \uB354 \uC791\uC740 \uAC83\uC73C\uB85C \uBC14\uAFB8\uAC70\uB098 \uD504\uB86C\uD504\uD2B8\uB97C \uC5B5\uC9C0\uB85C \uC904\uC5EC \uD488\uC9C8\uC744 \uB5A8\uC5B4\uB728\uB9AC\uAE30 \uC804\uC5D0, \uC5EC\uB7EC\uBD84\uC758 \uD504\uB86C\uD504\uD2B8 \uAD6C\uC870\uBD80\uD130 \uC815\uBE44\uD574\uBCF4\uC138\uC694. \uBC18\uBCF5\uB418\uB294 \uBB38\uB9E5\uC744 \uBAA8\uB378\uC774 \uB2E4\uC2DC \uACC4\uC0B0\uD558\uC9C0 \uC54A\uAC8C \uD558\uB294 \uAC83\uB9CC\uC73C\uB85C\uB3C4 \uBE44\uC6A9\uACFC \uC18D\uB3C4\uB77C\uB294 \uB450 \uB9C8\uB9AC \uD1A0\uB07C\uB97C \uC7A1\uC744 \uC218 \uC788\uC2B5\uB2C8\uB2E4.\\n\\n\uC9C0\uAE08 \uBC14\uB85C \uC5EC\uB7EC\uBD84\uC758 \uD504\uB86C\uD504\uD2B8\uB97C \uD655\uC778\uD574\uBCF4\uC138\uC694. \uBC18\uBCF5\uB418\uB294 \uC55E\uBD80\uBD84\uC744 \uCE90\uC2DC\uD560 \uC900\uBE44\uAC00 \uB418\uC168\uB098\uC694?\\n\\n:::info \uCC38\uACE0 \uC790\uB8CC\\n\uD504\uB86C\uD504\uD2B8 \uCE90\uC2F1 \uC774\uD574\uD558\uAE30 - \uD488\uC9C8\uC744 \uD76C\uC0DD\uD558\uC9C0 \uC54A\uACE0 LLM \uBE44\uC6A9\uC744 \uC904\uC774\uB294 \uBC29\uBC95 | LinkedIn\\n:::"}]}}')}}]);